script.code:
let allData = {{workflowparams:allData}}
const updatedSM = []
const saveAs = {{workflowparams:saveAs}}

// Helper function to format qty and price fields to 3 decimal places
const formatNumber = (value) => {
  if (value === null || value === undefined || value === "") return 0;
  return parseFloat(value).toFixed(3);
};

for (const [index, smLineItem] of allData.stock_movement.entries()) {
  if (!smLineItem.total_quantity || parseFloat(smLineItem.total_quantity) === 0) {
    continue;
  }
  // Format qty and price fields
  smLineItem.requested_qty = formatNumber(smLineItem.requested_qty);
  smLineItem.total_quantity = formatNumber(smLineItem.total_quantity);
  smLineItem.unit_price = formatNumber(smLineItem.unit_price);

  smLineItem.organization_id = allData.organization_id;
  smLineItem.issuing_plant = allData.issuing_operation_faci || null;
  smLineItem.receiving_plant = allData.receiving_operation_faci || null;
  smLineItem.line_index = index + 1;

  updatedSM.push(smLineItem)
}

allData.stock_movement = updatedSM

if ({{workflowparams:pageStatus}} === "Add") {
  allData.stock_movement_status = "Draft"
}

if (saveAs === "Draft") {
  if(allData.stock_movement_no_type !== -9999 && (
  !allData.stock_movement_no || allData.stock_movement_no === null || allData.stock_movement_no === ''
)) {
  allData.stock_movement_no = 'draft'
  }
} else {
  if (
  allData.stock_movement_no_type !== -9999 &&
  (!allData.stock_movement_no ||
    allData.stock_movement_no === null ||
    allData.stock_movement_no === "" ||
    allData.stock_movement_status !== "In Progress")
) {
  allData.stock_movement_no = 'issued'
  }
}

if (allData.acc_integration_type !== "No Accounting Integration") {
  allData.posted_status = "Unposted";
} else {
  allData.posted_status = "";
}

return {
  allData: allData,
  stock_movement_status: allData.stock_movement_status,
}

return {
  required_fields: JSON.stringify([
  { name: "stock_movement_no", label: "Stock Movement No" },
  { name: "movement_type", label: "Movement Type" },
  { name: "issue_date", label: "Issue Date" },
  { name: "issuing_operation_faci", label: "Issuing Operation Facility" },
  {
    name: "stock_movement",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    stock_movement_no: {{node:code_node_ISWz5KGY.data.allData.stock_movement_no}},
    movement_type: {{node:code_node_ISWz5KGY.data.allData.movement_type}},
    issue_date: {{node:code_node_ISWz5KGY.data.allData.issue_date}},
    issuing_operation_faci: {{node:code_node_ISWz5KGY.data.allData.issuing_operation_faci}},
    stock_movement: {{node:code_node_ISWz5KGY.data.allData.stock_movement}}
  })
}

const allData = {{node:code_node_ISWz5KGY.data.allData}}
const subformData = allData.stock_movement

let quantityFailed = 0
let quantityMessage

const balancesToProcess =
  allData.balance_index?.filter(
    (balance) => balance.sm_quantity && balance.sm_quantity > 0
  ) || [];

if (balancesToProcess.length === 0) {
  quantityFailed = 1
  quantityMessage = 'No quantity selected to issue'
}

return {
  quantityFailed: quantityFailed,
  quantityMessage: quantityMessage
};

const page_status = {{workflowparams:pageStatus}};
const stock_movement_status = {{node:code_node_ISWz5KGY.data.stock_movement_status}}
let allData;

if (page_status === "Add") {
  const rawData = {{node:add_node_1p1Kdkhz.data}}
  allData = Array.isArray(rawData) ? rawData[0] : rawData;
} else if (page_status === "Edit") {
  allData = {{node:get_node_7CFMbGI0.data.data}}
} else {
  allData = {{node:code_node_ISWz5KGY.data.allData}}
}

const subformData = allData.stock_movement;
const currentIndexRaw = {{node:get_cache_node_cFQ0jK2S.data}};
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;

const plant_id = allData.issuing_operation_faci;
const organization_id = allData.organization_id;
const stock_movement_no = allData.stock_movement_no;
const doc_date = allData.issue_date;

const item = subformData[index];
const material_id = item.item_selection;
const material_uom = item.quantity_uom || item.received_quantity_uom;
const total_quantity = item.total_quantity;
const location_id = item.location_id;
const batch_id = item.batch_id || null;
const remark = item.item_remark || null;
const remark2 = item.item_remark_2 || null;
const remark3 = item.item_remark_3 || null;
const inventory_category = "Unrestricted";

let tempDataParsed;

const tempData = item.temp_qty_data;
if (!tempData) {
  tempDataParsed = [];
} else {
  tempDataParsed = JSON.parse(tempData);
  tempDataParsed = tempDataParsed.filter(
    (tempData) => tempData.sm_quantity > 0
  );
  if (!Array.isArray(tempDataParsed)) {
    tempDataParsed = [];
  }
}

let balancesToProcess =
  allData.balance_index?.filter(
    (balance) =>
      balance.sm_quantity &&
      parseFloat(balance.sm_quantity) > 0 &&
      tempDataParsed.some(
        (tempData) =>
          tempData.material_id === balance.material_id &&
          tempData.location_id === balance.location_id &&
          (tempData.batch_id || "") === (balance.batch_id || "") &&
          (tempData.category || "Unrestricted") === (balance.category || "Unrestricted")
      )
  ) || [];

return {
  plant_id: plant_id,
  organization_id: organization_id,
  stock_movement_no: stock_movement_no,
  page_status: page_status,
  material_id: material_id,
  material_uom: material_uom,
  total_quantity: total_quantity,
  location_id: location_id,
  batch_id: batch_id,
  inventory_category: inventory_category,
  doc_date: doc_date,
  remark: remark,
  remark2: remark2,
  remark3: remark3,
  balancesToProcess: balancesToProcess,
  index: index,
  nextIndex: index + 1
};

const balancesToProcess = {{node:code_node_PeidsgXa.data.balancesToProcess}}
const currentIndexRaw = {{node:get_cache_node_V3E6xZfN.data}}
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0
const saveAs = {{workflowparams:saveAs}}
const stock_movement_status = {{node:code_node_ISWz5KGY.data.stock_movement_status}}

const balance = balancesToProcess[index];
const batch_id = balance.batch_id || null;
const location_id = balance.location_id;
const quantity = balance.sm_quantity;
let inventory_category = balance.category;
const manufacturing_date = balance.manufacturing_date || null;
const expired_date = balance.expired_date || null;

return {
  batch_id: batch_id,
  location_id: location_id,
  quantity: quantity,
  inventory_category: inventory_category,
  manufacturing_date: manufacturing_date,
  expired_date: expired_date,
  index: index,
  nextIndex: index + 1
};

const tableSM = {{node:code_node_ISWz5KGY.data.allData.stock_movement}}

const uniqueItemIds = [
  ...new Set(
    tableSM
      .filter((item) => item.item_selection)
      .map((item) => item.item_selection),
  ),
];

const date = new Date().toISOString();
const updates = [];

for (const itemId of uniqueItemIds) {
  updates.push({
    id: itemId,
    last_transaction_date: date,
  });
}

return {
  updates: updates,
};
